import android.content.Context
import androidx.appcompat.app.AppCompatActivity
import kotlinx.android.synthetic.main.activity_login.*
 
class LoginManager(context: Context) : AppCompatActivity() {
    private val sharedPref = getSharedPreferences("auth", MODE_PRIVATE)
    
    fun saveUserIDAndToken (userId: String, token:String){   // Saving user ID and Token in Shared Preferences 
        with(sharedPref.edit()) {                          // Using Edit to avoid ConcurrentModificationException when reading the data later on...     
            putString("USER_ID", userId)                     // ...and saving it there instead of directly into shared preferences  
            putString("TOKEN", token )                       // Saving Token in Shared Preferences 
            
        }   
     }      
        
    fun loadUserInfo(): Pair<String, String> {              // Loading user ID and the saved AuthToken from SharePreferences  
            val id = sharedPref.getString("USER_ID", "")     
            val token=sharedPref.getString("TOKEN","")      
             return Pair(id ?: "",token?: "") 
    }    
}